// ─── Parse incoming WhatsApp Cloud API webhook payload ───
const body = $input.first().json.body;
const entry = body?.entry?.[0];
const change = entry?.changes?.[0];
const value = change?.value;
const messages = value?.messages;

if (!messages || messages.length === 0) {
  return [{ json: { action: 'ignore', from: null, response: null, leadData: null } }];
}

const message = messages[0];
const from = message.from;
const msgType = message.type;
let userText = '';

if (msgType === 'text') {
  userText = (message.text?.body || '').trim();
} else if (msgType === 'interactive') {
  if (message.interactive?.type === 'button_reply') {
    userText = message.interactive.button_reply?.id || '';
  } else if (message.interactive?.type === 'list_reply') {
    userText = message.interactive.list_reply?.id || '';
  }
}

// ─── FAQ data (mirrors website chatbot) ───
const FAQ = {
  about: {
    label: 'About Programme',
    reply: "The Business & Real Estate Management (BREM) Program is Lotlite's flagship professional stream. It combines micro-market evaluation, advanced real estate valuation models, PropTech integration, and AI-powered automation — preparing graduates for leadership roles in real estate investment, operations, and advisory.",
    followUps: ['curriculum', 'admission', 'fees']
  },
  admission: {
    label: 'Admissions',
    reply: "To be eligible, applicants need a completed online application form, solid academic transcripts, and a brief personal interview. We welcome graduates from any discipline with a strong interest in real estate and business management. Applications are open year-round.",
    followUps: ['apply', 'fees', 'contact']
  },
  curriculum: {
    label: 'Curriculum',
    reply: "The curriculum spans four core pillars:\n\n\u2022 Real Estate Valuation & Micro-Market Analysis\n\u2022 PropTech & Digital Tools for Property Management\n\u2022 AI Agents & Automation in Real Estate Operations\n\u2022 Investment Strategy, Deal Structuring & Portfolio Management\n\nEach module blends theory with live case studies and industry mentorship.",
    followUps: ['about', 'fees']
  },
  fees: {
    label: 'Fees & Aid',
    reply: "Tuition is structured competitively with a flexible 3-part installment plan. A 10% discount applies for full upfront semester payment. We also offer merit-based scholarships and need-based fee waivers — contact admissions for the full fee schedule.",
    followUps: ['admission', 'apply', 'contact']
  },
  career: {
    label: 'Career Outcomes',
    reply: "Graduates pursue roles such as:\n\n\u2022 Real Estate Investment Analyst\n\u2022 Property Portfolio Manager\n\u2022 PropTech Consultant\n\u2022 Real Estate Fund Associate\n\u2022 Urban Development Advisor\n\nOur placement cell partners with leading developers, REITs, and consulting firms.",
    followUps: ['about', 'curriculum', 'apply']
  },
  apply: {
    label: 'Apply Now',
    reply: "Applying is simple:\n\n1. Fill out the online application form\n2. Upload your academic transcripts\n3. Complete a short personal interview (within 3 working days)\n4. Receive your admission decision within 7 days\n\nNeed help? Our advisors are happy to assist!",
    followUps: ['admission', 'fees', 'contact']
  }
};

// ─── Keyword matching (same logic as website chatbot) ───
function matchKeywords(text) {
  const t = text.toLowerCase();
  const greetings = ['hello', 'hi', 'hey', 'greetings', 'good morning', 'good afternoon', 'good evening', 'start', 'menu'];
  if (greetings.some(g => t.includes(g))) return 'greeting';
  if (t.includes('career') || t.includes('placement') || t.includes('job') || t.includes('outcome') || t.includes('salary') || t.includes('reit') || t.includes('intern')) return 'career';
  if (t.includes('curriculum') || t.includes('syllabus') || t.includes('module') || t.includes('subject') || t.includes('topic')) return 'curriculum';
  if (t.includes('apply') || t.includes('application') || t.includes('enroll') || t.includes('register') || t.includes('join') || t.includes('sign up')) return 'apply';
  if (t.includes('admission') || t.includes('eligibility') || t.includes('criteria') || t.includes('requirement') || t.includes('eligible') || t.includes('qualify')) return 'admission';
  if (t.includes('fee') || t.includes('cost') || t.includes('price') || t.includes('tuition') || t.includes('scholarship') || t.includes('discount') || t.includes('installment') || t.includes('financial')) return 'fees';
  if (t.includes('brem') || t.includes('program') || t.includes('programme') || t.includes('real estate') || t.includes('about') || t.includes('course') || t.includes('proptech') || t.includes('duration')) return 'about';
  if (t.includes('contact') || t.includes('advisor') || t.includes('talk') || t.includes('call') || t.includes('speak') || t.includes('phone') || t.includes('reach') || t.includes('mentor')) return 'contact';
  return 'fallback';
}

// ─── WhatsApp message builders ───
function buildMainMenu(to) {
  return {
    messaging_product: 'whatsapp',
    to,
    type: 'interactive',
    interactive: {
      type: 'list',
      body: { text: 'Greetings! Welcome to the Lotlite Academic Help Desk. \ud83c\udf93\n\nI am your Lotlite Support Assistant. How can I help you today? Select a topic below or type your question.' },
      action: {
        button: 'View Topics',
        sections: [{
          title: 'Available Topics',
          rows: [
            { id: 'about',     title: 'About the Programme',    description: 'Learn about the BREM Program' },
            { id: 'admission', title: 'Admissions & Eligibility', description: 'Requirements & criteria' },
            { id: 'curriculum',title: 'Curriculum',              description: 'Modules & what you will learn' },
            { id: 'fees',      title: 'Fees & Scholarships',     description: 'Costs & financial aid options' },
            { id: 'career',    title: 'Career Outcomes',         description: 'Job roles & placements' },
            { id: 'apply',     title: 'Apply Now',               description: 'How to apply step by step' },
            { id: 'contact',   title: 'Talk to an Advisor',      description: 'Get personal guidance' }
          ]
        }]
      }
    }
  };
}

function buildButtons(to, text, followUps) {
  const valid = (followUps || []).filter(id => FAQ[id] || id === 'contact');
  if (valid.length === 0) return buildText(to, text);
  const buttons = valid.slice(0, 3).map(id => ({
    type: 'reply',
    reply: {
      id,
      title: (id === 'contact' ? 'Talk to Advisor' : (FAQ[id]?.label || id)).substring(0, 20)
    }
  }));
  return {
    messaging_product: 'whatsapp',
    to,
    type: 'interactive',
    interactive: { type: 'button', body: { text }, action: { buttons } }
  };
}

function buildText(to, text) {
  return {
    messaging_product: 'whatsapp',
    to,
    type: 'text',
    text: { body: text }
  };
}

// ─── Session state management via workflow static data ───
const staticData = $getWorkflowStaticData('global');
if (!staticData.sessions) staticData.sessions = {};

const now = Date.now();
for (const phone of Object.keys(staticData.sessions)) {
  if (now - (staticData.sessions[phone].updatedAt || 0) > 86400000) {
    delete staticData.sessions[phone];
  }
}

const session = staticData.sessions[from] || { state: 'idle', name: '', updatedAt: now };
session.updatedAt = now;

let response = null;
let action = 'send_message';
let leadData = null;

// ─── Conversation flow (mirrors website chatbot states) ───
if (session.state === 'awaiting_name') {
  if (!userText || userText.length < 2) {
    response = buildText(from, 'Please enter your full name (at least 2 characters).');
  } else {
    session.name = userText;
    session.state = 'awaiting_phone';
    staticData.sessions[from] = session;
    response = buildText(from, `Nice to meet you, ${userText}! \ud83d\udcf1\n\nWhat is your phone number? (include country code if outside India, e.g. +919876543210)`);
  }
} else if (session.state === 'awaiting_phone') {
  const digits = userText.replace(/\D/g, '');
  if (digits.length < 10) {
    response = buildText(from, "That doesn't look like a valid phone number. Please enter at least 10 digits (e.g. 9876543210 or +919876543210).");
  } else {
    const capturedName = session.name;
    action = 'submit_lead';
    leadData = {
      fullName: capturedName,
      phone: userText.trim(),
      source: 'WhatsApp Chatbot',
      lead_tags: ['Lotlite Edu', 'WhatsApp']
    };
    session.state = 'idle';
    session.name = '';
    staticData.sessions[from] = session;
    response = buildButtons(
      from,
      `Thank you, ${capturedName}! \u2705\n\nOur advisor will call you shortly. Is there anything else I can help you with?`,
      ['about', 'admission', 'fees']
    );
  }
} else {
  // Idle state — handle FAQ button taps or free-text keywords
  if (FAQ[userText]) {
    const faq = FAQ[userText];
    response = buildButtons(from, faq.reply, faq.followUps);
  } else if (userText === 'contact') {
    session.state = 'awaiting_name';
    staticData.sessions[from] = session;
    response = buildText(from, "Sure! I'll connect you with an advisor. \ud83d\ude0a\n\nFirst, what is your full name?");
  } else {
    const match = matchKeywords(userText);
    if (match === 'greeting' || match === 'fallback') {
      response = buildMainMenu(from);
    } else if (match === 'contact') {
      session.state = 'awaiting_name';
      staticData.sessions[from] = session;
      response = buildText(from, "Sure! I'll connect you with an advisor. \ud83d\ude0a\n\nFirst, what is your full name?");
    } else if (FAQ[match]) {
      const faq = FAQ[match];
      response = buildButtons(from, faq.reply, faq.followUps);
    } else {
      response = buildMainMenu(from);
    }
  }
}

return [{ json: { action, from, response, leadData } }];
